        "then": "Only the 2026-01-15 event appears in the report"
      },
      {
        "criterion": "Download returns a file attachment",
        "given": "A valid report request",
        "when": "The response is returned",
        "then": "Response includes Content-Type matching format (text/csv or application/pdf) and Content-Disposition: attachment with a filename"
      },
      {
        "criterion": "Large date range triggers async path",
        "given": "A report request spanning more than 90 days",
        "when": "The request is submitted via POST /reports/jobs",
        "then": "A 202 Accepted response is returned with a job ID, and GET /reports/jobs/{id} returns status (pending|processing|completed|failed) and a download link when completed"
